external_knowledge:
- 'shining stars' refers to the researchers who have significant contributions to studies;
- 'principal investigative prowess' indicates researchers holding the position of 'Principal Investigator';
- 'studies with a golden touch' implies studies with an AUC greater than 0.9;
- 'illustrious endeavors' refers to the studies where the researchers are involved;
- 'from the most prolific to the less' indicates ordering the results from the highest number of studies involved to the lowest.

sql:
SELECT s.study_id, s.title, r.first_name, r.last_name
FROM studies s
JOIN researchers r ON s.first_author = r.last_name;

SELECT DISTINCT first_author
FROM studies
WHERE sample_size > 1000;
